const e={hardwareBrowser:{intro:{t:0,b:{t:2,i:[{t:3}],s:"Durchsuche eine kuratierte Referenz für 3D-Druck-Hardware — Schrittmotoren, Treiber, Boards, Sensoren, Hotends, Lüfter, Hosts, Düsen, Extruder, Filamente und mehr — nach Name, Hersteller, Kategorie oder beliebiger Spezifikation."}},help:{guide:{t:0,b:{t:2,i:[{t:3}],s:"Hilfe"}},guideTitle:{t:0,b:{t:2,i:[{t:3}],s:"Über den Hardware Browser"}},close:{t:0,b:{t:2,i:[{t:3}],s:"Schließen"}},howToRead:{t:0,b:{t:2,i:[{t:3}],s:"Verwendung"}},steps:[{t:0,b:{t:2,i:[{t:3}],s:"Tippe in das Suchfeld, um einen Namen, Hersteller oder beliebigen Spezifikationswert zu finden."}},{t:0,b:{t:2,i:[{t:3}],s:"Grenze die Auswahl mit den Filtern nach Kategorie oder Hersteller ein."}},{t:0,b:{t:2,i:[{t:3}],s:"Jede Ergebniskarte zeigt die Spezifikationen der Komponente; blättere mit Zurück / Weiter."}}],topics:{search:{title:{t:0,b:{t:2,i:[{t:3}],s:"Suchen"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Die Suche findet Treffer überall — Hersteller, Modellname, Kategorie, Unterabschnitt oder beliebiger Spezifikationswert. Kombiniere sie mit den Filtern für Kategorie und Hersteller, um die Auswahl einzugrenzen. Die Ergebnisse sind seitenweise aufgeteilt; die Gesamtanzahl spiegelt alle Treffer wider, nicht nur die aktuelle Seite."}}},categories:{title:{t:0,b:{t:2,i:[{t:3}],s:"Kategorien"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Komponenten sind in Kategorien gruppiert (Schrittmotoren, Treiber, Boards, Sensoren, Hotends, Lüfter/Stromversorgung, Hosts, Bewegung, Düsen, Extruder, Filamente, Elektronik, Kameras/Displays). Wähle eine aus, um nur diesen Typ zu durchsuchen."}}},manufacturers:{title:{t:0,b:{t:2,i:[{t:3}],s:"Hersteller & Spezifikationen"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Dies ist eine kuratierte Referenz zum Vergleichen, kein Shop — die Werte stammen aus Hersteller-Datenblättern und Community-Daten und können hinter den neuesten Produkten zurückliegen. Bestätige sie vor dem Kauf oder Konfigurieren immer beim Hersteller."}}},glossary:{title:{t:0,b:{t:2,i:[{t:3}],s:"Glossar"}},body:{t:0,b:{static:"",t:2,i:[]}}}},glossary:{category:{term:{t:0,b:{t:2,i:[{t:3}],s:"Kategorie"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Der Hardware-Typ, zu dem eine Komponente gehört (z. B. Hotends, Schrittmotoren, Sensoren)."}}},manufacturer:{term:{t:0,b:{t:2,i:[{t:3}],s:"Hersteller"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Das Unternehmen, das das Bauteil herstellt (z. B. E3D, BIGTREETECH, LDO Motors)."}}},spec:{term:{t:0,b:{t:2,i:[{t:3}],s:"Spezifikation"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Ein Datenblatt-Attribut einer Komponente — Strom, Spannung, Maximaltemperatur, Abmessungen und so weiter."}}}}},search:{placeholder:{t:0,b:{t:2,i:[{t:3}],s:"Hardware suchen…"}},button:{t:0,b:{t:2,i:[{t:3}],s:"Suchen"}},category:{t:0,b:{t:2,i:[{t:3}],s:"Kategorie"}},allCategories:{t:0,b:{t:2,i:[{t:3}],s:"Alle Kategorien"}},manufacturer:{t:0,b:{t:2,i:[{t:3}],s:"Hersteller"}},manufacturerPlaceholder:{t:0,b:{t:2,i:[{t:3}],s:"Beliebiger Hersteller"}}},results:{total:{t:0,b:{t:2,i:[{t:4,k:"count"},{t:3,v:" Treffer"}]}},none:{t:0,b:{t:2,i:[{t:3}],s:"Keine Komponenten entsprechen deiner Suche."}},showing:{t:0,b:{t:2,i:[{t:3,v:"Zeige "},{t:4,k:"from"},{t:3,v:"–"},{t:4,k:"to"},{t:3,v:" von "},{t:4,k:"total"}]}},prev:{t:0,b:{t:2,i:[{t:3}],s:"Zurück"}},next:{t:0,b:{t:2,i:[{t:3}],s:"Weiter"}}},states:{loading:{t:0,b:{t:2,i:[{t:3}],s:"Suche läuft…"}},error:{t:0,b:{t:2,i:[{t:3}],s:"Die Hardware-Datenbank konnte nicht geladen werden."}},retry:{t:0,b:{t:2,i:[{t:3}],s:"Erneut versuchen"}}},tabs:{catalog:{t:0,b:{t:2,i:[{t:3}],s:"Katalog"}},search:{t:0,b:{t:2,i:[{t:3}],s:"Alles suchen"}}},catalog:{searchAll:{t:0,b:{t:2,i:[{t:3}],s:"Alles suchen"}},items:{t:0,b:{t:2,i:[{t:4,k:"n"},{t:3,v:" Einträge"}]}}}}};export{e as default};
